#include <iostream>
using namespace std;

int factorial(int n) {
    // Base condition
    if (n <= 1)
        return 1;
    // Recursive case
    else
        return n * factorial(n - 1);
}

int main() {
    int num = 5;
    cout << "Factorial of " << num << " = " << factorial(num);
    return 0;
}

