#include <iostream>
using namespace std;

class Base {
public:
    virtual void show() { cout << "Base\n"; }
};

class Derived : public Base {
public:
    void show() { cout << "Derived\n"; }
};

int main() {
    // Implicit casting
    int a = 10;
    double b = a;  // implicit: int to double
    cout << "Implicit: " << b << endl;

    // Explicit casting (C-style)
    double c = 9.8;
    int d = (int)c;  // explicit: double to int
    cout << "C-style cast: " << d << endl;

    // static_cast
    double e = 15.7;
    int f = static_cast<int>(e);
    cout << "static_cast: " << f << endl;

    // dynamic_cast (safe downcasting)
    Base* basePtr = new Derived();
    Derived* derivedPtr = dynamic_cast<Derived*>(basePtr);
    if (derivedPtr) {
        cout << "dynamic_cast succeeded" << endl;
        derivedPtr->show();
    }

    // const_cast
    const int g = 20;
    int* h = const_cast<int*>(&g);
    *h = 30;  // Undefined behavior but compiles
    cout << "const_cast modified: " << *h << endl;

    return 0;
}

def factorial(n):
    """Recursive function to find factorial"""
    # Base condition
    if n <= 1:
        return 1
    # Recursive case
    else:
        return n * factorial(n - 1)

